package com.example.hr.service;

import javax.jws.WebService;

@WebService(endpointInterface = "com.example.hr.service.EmployeeManagementService",
            serviceName = "EmployeeManagementService",
            portName = "EmployeeManagementPort",
            targetNamespace = "http://service.hr.example.com/")
public class EmployeeManagementServiceImpl implements EmployeeManagementService {

    @Override
    public String updateSalary(String employeeId, double newSalary) {
        System.out.println("HR System: Received request to update salary for employee " + employeeId + " to " + newSalary);
        // In a real HR system, this would involve database updates, validation, etc.
        if (newSalary <= 0) {
            return "Error: New salary must be positive for employee " + employeeId;
        }
        return "Salary for employee " + employeeId + " successfully updated to " + newSalary;
    }

    @Override
    public String recordPerformanceReview(String employeeId, int rating, String comments) {
        System.out.println("HR System: Received request to record performance review for employee " + employeeId + ". Rating: " + rating + ", Comments: '" + comments + "'");
        // In a real HR system, this would store the review in a database.
        if (rating < 1 || rating > 5) {
            return "Error: Rating must be between 1 and 5 for employee " + employeeId;
        }
        return "Performance review recorded for employee " + employeeId + " with rating " + rating + ". Comments: '" + comments + "'";
    }

    @Override
    public String terminateEmployee(String employeeId, String reason) {
        System.out.println("HR System: Received request to terminate employee " + employeeId + " due to: " + reason);
        // In a real HR system, this would update employee status, trigger off-boarding processes, etc.
        if (reason == null || reason.trim().isEmpty()) {
            return "Error: Termination reason cannot be empty for employee " + employeeId;
        }
        return "Employee " + employeeId + " has been successfully terminated. Reason: " + reason;
    }
}

